fn factorial(n: i32) -> Result<u128, String> {
    if n < 0 {
        return Err(String::from("El número debe ser no negativo"));
    }
    if n == 0 {
        return Ok(1);
    }

    factorial(n - 1).map(|res| res * n as u128)
}

fn main() {
    let test_cases = [5, 0, -3, 10];

    for &num in &test_cases {
        match factorial(num) {
            Ok(result) => println!("El factorial de {} es {}", num, result),
            Err(e) => println!("Error para {}: {}", num, e),
        }
    }
}
