/**
 * Realiza una solicitud GET con lógica de reintentos.
 * 
 * @param {string} url - La URL de la API.
 * @param {object} options - Opciones adicionales para fetch.
 * @param {number} maxRetries - Número máximo de intentos (por defecto 3).
 * @returns {Promise<any>} - La respuesta parseada como JSON.
 * @throws {Error} - Si se agotan los reintentos o ocurre un error crítico.
 */
const fetchDataWithRetry = async (url, options = {}, maxRetries = 3) => {
  let lastError;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, {
        method: 'GET',
        ...options,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      lastError = error;
      console.warn(`Intento ${attempt} fallido: ${error.message}`);

      if (attempt < maxRetries) {
        // Espera exponencial (backoff): 500ms, 1000ms...
        const delay = Math.pow(2, attempt - 1) * 500;
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw new Error(`Operación fallida tras ${maxRetries} intentos. Último error: ${lastError.message}`);
};

// --- Ejemplo de uso ---
const API_URL = 'https://jsonplaceholder.typicode.com/posts/1';

(async () => {
  try {
    const data = await fetchDataWithRetry(API_URL);
    console.log('Datos obtenidos con éxito:', data);
  } catch (error) {
    console.error('Error final en la aplicación:', error.message);
  }
})();
